window.__QUIZ_DATA__=[{"id":"objective>Mathematics>1995>1","subject":"Mathematics","year":"1995","type":"Objective","topic":"NUMBER AND NUMERATION : NUMBER BASES","question":"Find (1012)2, expressing the answer in base 2.","images":[],"options":{"A":"10101","B":"11001","C":"10010","D":"11101"},"answer":"B","explanation":"(1012)2 ==> 1012 = 1 x 22 + 0 x 21 + 1 x 20  = 1 x 4 + 0 + 1 (Recall xo = 1)  = 4 + 1 = 5; (1012)2 = (510)2 = 25.","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1995>2","subject":"Mathematics","year":"1995","type":"Objective","topic":"NUMBER AND NUMERATION : RATIO, PROPORTIONS AND RATES","question":"If three children share \u20a610.50 among themselves in the ratio 6:7:8, how much is the largest share?","images":[],"options":{"A":"\u20a63.00","B":"\u20a63.50","C":"\u20a64.00","D":"\u20a64.50"},"answer":"C","explanation":"Total amount = \u20a610.50; Ratio = 6 : 7 : 8; largest share = 8  \u2234 Largestamount=86 + 7 + 8x\u20a610.50  =821x\u20a610.50  = \u20a64.00","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1995>3","subject":"Mathematics","year":"1995","type":"Objective","topic":"NUMBER AND NUMERATION : NUMBERS IN STANDARD FORM-SCIENTIFIC NOTATION","question":"Express 0.000834 in standard form.","images":[],"options":{"A":"8.34 x 10-4","B":"8.34 x 10-3","C":"8.34 x 103","D":"8.34 x 104"},"answer":"A","explanation":"0.0000834=8341000000=834x11000000  = 8.34 x 100 x 10-6 = 8.34 x 102 x 10-6    = 8.34 x 10-4","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1995>4","subject":"Mathematics","year":"1995","type":"Objective","topic":"NUMBER AND NUMERATION : LAWS OF INDICES","question":"Simplify 0.027-1/3","images":[],"options":{"A":"31/3","B":"3","C":"3/10","D":"1/3"},"answer":"A","explanation":"0.027-1/3 = (271000)-1/3 = (127/1000)1/3  = 1(\u221b27/1000) = 13/10  = 103  = 31/3","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1995>5","subject":"Mathematics","year":"1995","type":"Objective","topic":"NUMBER AND NUMERATION : LOGARITHMS","question":"Given that log2a = log84, find a.","images":[],"options":{"A":"21/2","B":"41/3","C":"42/3","D":"22/3"},"answer":"D","explanation":"log2a = log84; Let log84 = x; then 8x = 4    = 23x = 22    \u2234 3x = 2; x = 2/3    Hence, log2a = 2/3;    \u2234 a = 22/3","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1995>6","subject":"Mathematics","year":"1995","type":"Objective","topic":"NUMBER AND NUMERATION : PROFIT AND LOSS","question":"By selling some crates of soft drinks for \u20a6600.00, a dealer makes a profit of 50%. How much did the dealer pay for the drinks?","images":[],"options":{"A":"\u20a61200.00","B":"\u20a6900.00","C":"\u20a6450.00","D":"\u20a6400.00"},"answer":"D","explanation":"Selling price = \u20a6 600; Profit = 50%    Cost price = x;  x + 50x/100 = \u20a6600    = x + x/2 = \u20a6600; 3x/2 = 600 => 3x = \u20a61200    x = \u20a6400.00","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1995>7","subject":"Mathematics","year":"1995","type":"Objective","topic":"NUMBER AND NUMERATION : SEQUENCE AND SERIES","question":"Find the nth term Un of the A.P., 11, 4, -3,..","images":[],"options":{"A":"Un = 19 + 7n","B":"Un = 19 - 7n","C":"Un = 18 - 7n","D":"Un = 18 + 7n"},"answer":"C","explanation":"Un = a + (n - 1)d;  where a = 11; d = -7  Un = 11 + (n - 1)(-7) = 11 - 7n + 7 = 18 - 7n","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1995>8","subject":"Mathematics","year":"1995","type":"Objective","topic":"NUMBER AND NUMERATION : SEQUENCE AND SERIES","question":"If 16/9, x, 1, y are in geometric progression (G.P). Find the product of x and y.","images":[],"options":{"A":"9/16","B":"3/4","C":"1","D":"4/3"},"answer":"C","explanation":"16/9, x, 1, y are in G.P.  x(16/9) = 1x  x2 = 16/9;  x = 4/3    a = 16/9; ar = 4/3    ara = r = (4/3)(16/9)  x = 4/3 and y = 3/4    Hence, product (xy) = 4/3 x 3/4 = 1","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1995>9","subject":"Mathematics","year":"1995","type":"Objective","topic":"NUMBER AND NUMERATION : SETS","question":"If R = {2, 4, 6, 7} and S = {1, 2, 4, 8} then R\u22c3S equals","images":[],"options":{"A":"{1, 2, 4, 6, 7, 8}","B":"{1, 2, 4, 7, 8}","C":"{1, 4, 7, 8}","D":"{2, 6, 7}"},"answer":"A","explanation":"R = {2, 4, 6, 7}, S = {1, 2, 4, 8}  R \u22c3 S ==> element in R and S together without replacement.  \u2234 R \u22c3 S = {1, 2, 4, 6, 7, 8}","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1995>10","subject":"Mathematics","year":"1995","type":"Objective","topic":"NUMBER AND NUMERATION : SETS","question":"In the diagram below, the shaded portion is","images":["data:image/png;base64,"],"options":{"A":"P1 \u22c2 R","B":"Q1 \u22c2 R","C":"P1 \u22c2 Q  R","D":"(P\u22c3Q)1 \u22c2 R"},"answer":"A","explanation":"Shaded is the portion that does not fall in field of P => P1; it is the area in R  Area common to P1 and R is denoted as P1 \u22c2 R","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1995>11","subject":"Mathematics","year":"1995","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"Findthevaluesofxforwhichtheexpressionisundefined:6x - 1x2 + 4x - 5","images":[],"options":{"A":"+4 or +1","B":"-5 or +1","C":"-5 or -1","D":"+5 or -1"},"answer":"B","explanation":"A fraction is undefined when when its denominator is zero  i.e 6x - 1x2 + 4x - 5 is undefined when x2 + 4x - 5 = 0  \u2234 (x + 5)(x - 1) = 0; x = -5 or 1.","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1995>12","subject":"Mathematics","year":"1995","type":"Objective","topic":"ALGEBRAIC PROCESSES : LINEAR INEQUALITIES","question":"Which of the following could be the inequality illustrated in the sketch graph below?","images":["data:image/png;base64,"],"options":{"A":"y \u2265 -2x + 3","B":"y \u2264 -3x + 3","C":"y \u2264 3x + 2","D":"y \u2264 x + 3"},"answer":"B","explanation":"The gradient of the line passing through points (0, 3) and (1, 0)  = y2 - y1x2 - x1 ==> 0 - 31 - 0 = -31 = -3  Equation of this line ==> y = mx + c    y = -3x + 3;  since the line is solid;    The equation represented by the graph is y \u2264 -3x + 3","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1995>13","subject":"Mathematics","year":"1995","type":"Objective","topic":"ALGEBRAIC PROCESSES : LINEAR INEQUALITIES","question":"Solve the inequality 1/3(2x - 1)","images":[],"options":{"A":"x","B":"x","C":"x","D":"x"},"answer":"D","explanation":"1/3(2x - 1)  = 2x - 1  = 2x  \u2234 x","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1995>14","subject":"Mathematics","year":"1995","type":"Objective","topic":"ALGEBRAIC PROCESSES : QUADRATIC EQUATIONS","question":"What is the smaller value of x for which x2 - 3x + 2 = 0?","images":[],"options":{"A":"1","B":"2","C":"3","D":"4"},"answer":"A","explanation":"x2 - 3x + 2 = 0. By factorization, (x - 2)(x - 1) = 0  x = 2 or 1  The smaller value is 1","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1995>15","subject":"Mathematics","year":"1995","type":"Objective","topic":"ALGEBRAIC PROCESSES : EXPANSION AND FACTORISATION","question":"Factorize the expression x(a- c) + y(c - a)","images":[],"options":{"A":"(a - c)(y - x)","B":"(a - c)(x - y)","C":"(a + c)(x - y)","D":"(a + c)(x + y)"},"answer":"B","explanation":"Factorize x(a - c) + y(c - a) ==> -x(c - a) + y(c - a)  = (-x + y)(c - a)  = (y - x)(c - a)  = -(a - c)(y - x)  = (a - c)(x - y)","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1995>16","subject":"Mathematics","year":"1995","type":"Objective","topic":"NUMBER AND NUMERATION : VARIATION","question":"If y \u221d 1/x2 and x = 3; when y = 4; find y when x = 2","images":[],"options":{"A":"1","B":"3","C":"9","D":"18"},"answer":"C","explanation":"y \u221d 1/x2;  y = k/x2;  when x = 3, y = 4.    y = k/32;  4 = k/9    41 = k9; k = 36  Equation y = 36/x2;  Now when x = 2    y = 36/22 = 36/4 = 9","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1995>17","subject":"Mathematics","year":"1995","type":"Objective","topic":"ALGEBRAIC PROCESSES : QUADRATIC EQUATIONS","question":"Solve the equation 3x2 + 25x - 18 = 0","images":[],"options":{"A":"-3, 2","B":"-2, 3","C":"-2, 9","D":"-9, 2/3"},"answer":"D","explanation":"3x2 + 25x - 18 = 0; (3x - 2)(x + 9) = 0  Either 3x - 2 = 0 or x + 9 = 0  3x = 2 or x = -9  \u2234 x = 2/3 or -9","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1995>18","subject":"Mathematics","year":"1995","type":"Objective","topic":"ALGEBRAIC PROCESSES : QUADRATIC EQUATIONS","question":"Solve the equation (x + 2)(x - 7) = 0","images":[],"options":{"A":"x = -1 or 8","B":"x = -2 or 7","C":"x = -4 or 5","D":"x = -3 or 6"},"answer":"B","explanation":"(x + 2)(x - 7) = 0;  either x + 2 = 0 or x - 7 = 0  x = -2 or 7","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1995>19","subject":"Mathematics","year":"1995","type":"Objective","topic":"ALGEBRAIC PROCESSES : SIMULTANEOUS LINEAR EQUATIONS IN TWO VARIABLES","question":"Solve the following simultaneous equations: x + y = 3/2, x - y = 5/2. And use your result to find the value of 2y + x.","images":[],"options":{"A":"-2","B":"-1","C":"1/2","D":"1"},"answer":"D","explanation":"x + y = 3/2    x - y = 5/2    2x = 8/2 (By adding the two equations above)    => 2x = 4. Hence, x = 2    Substitute 2 for x in eqn (1)    2 + y = 3/2 => y = -1/2    value of (2y + x) = [2(-1/2) + 2] = (-1 + 2) = 1","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1995>20","subject":"Mathematics","year":"1995","type":"Objective","topic":"ALGEBRAIC PROCESSES : GRAPHS OF LINEAR AND QUADRATIC FUNCTIONS","question":"Use the graph of y = 3x2 + x - 7 to answer questions  below .       What is the minimum value of y?","images":["data:image/png;base64,"],"options":{"A":"-10","B":"-7","C":"-4","D":"-1"},"answer":"B","explanation":"Minimum value can be read directly from the y axis of the graph to be the lowest attainable value of the function at the point where it turns. And this occurs at y = -7.","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1995>21","subject":"Mathematics","year":"1995","type":"Objective","topic":"ALGEBRAIC PROCESSES : GRAPHS OF LINEAR AND QUADRATIC FUNCTIONS","question":"Use the graph of y = 3x2 + x - 7 to answer questions  below .     Find the roots of the equation y  = 3x2 + x - 7.","images":["data:image/png;base64,"],"options":{"A":"1.0 and -1.2","B":"1.1 and -1.3","C":"1.4 and -1.7","D":"2.0 and -1.9"},"answer":"C","explanation":"The roots of the equation are the values of x at the point where the graph crosses the x-axis. And this can be read from the graph to be 1.4 and -1.7.","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1995>22","subject":"Mathematics","year":"1995","type":"Objective","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"In the diagram below, |AB| = 12 cm, |AE| = 8cm, |DC| = 9 cm and BD||DC.","images":["data:image/png;base64,"],"options":{"A":"10 cm","B":"9 cm","C":"8 cm","D":"6 cm"},"answer":"D","explanation":"Triangle ABE is similar to CDE     \u2234 The sides are in common ratio.  ==> ECAE = ABCD ==> EC8 = 912  EC = 8 x 912 EC = 6 cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1995>23","subject":"Mathematics","year":"1995","type":"Objective","topic":"MENSURATION : AREAS","question":"The diagonals AC and BD of a rhombus ABCD are 16 cm and 12 cm long respectively. Calculate the area of the rhombus.","images":[],"options":{"A":"24 cm2","B":"36 cm2","C":"48 cm2","D":"96 cm2"},"answer":"D","explanation":"Given that AC = 16 cm and BD = 12 cm. If O is the center. The diagonals of a rhombus meet at 90o.  AO = AC/2 = 8cm;  BO = BD/2 = 6 cm  AB2 = AO2 + OB2 (pythagoras theorem)  AB2 = 64 + 36 = 100; AB = 10 cm  Area  of \u2206ABO = 1/2 x 8 x 6 = 24 cm2  Area of rhombus = 4 x area of \u2206ABO  ==> 4 x 24 = 96 cm2.","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1995>24","subject":"Mathematics","year":"1995","type":"Objective","topic":"MENSURATION : VOLUMES","question":"A water tank of height 1/2 m has a square base of side 11/2 m. If it is filled with water from a water tanker holding 1500 litres, how many litres of water are left in the water tanker?   [1000 litres = 1 m3]","images":[],"options":{"A":"37.5 litres","B":"375 litres","C":"3750 litres","D":"37500 litres"},"answer":"B","explanation":"Capacity of water tank =  (1/2 x 3/2 x 3/2) m3 = 9/8 m3  = 9/8 x 1000 litres = 1125 litres.  water tankers capacity = 1500 litres  Amount of water remaining = (1500 - 1125) litres = 375 litres","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1995>25","subject":"Mathematics","year":"1995","type":"Objective","topic":"MENSURATION : AREAS","question":"A cylindrical container, closed at both ends, has a radius of 7 cm and height 5 cm.    Use this information to answer questions below.    Find the total surface area of the container.","images":[],"options":{"A":"35 cm2","B":"154 cm2","C":"220 cm2","D":"528 cm2"},"answer":"D","explanation":"if h = height and r = radius  Total surface area = 2\u03c0r2 + 2\u03c0rh = 2\u03c0r(r + h)  => 2 x 22/7 x 7 x (7 + 5)  => 44 x 12 = 528 cm2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1995>26","subject":"Mathematics","year":"1995","type":"Objective","topic":"MENSURATION : VOLUMES","question":"A cylindrical container, closed at both ends, has a radius of 7 cm and height 5 cm.    Use this information to answer questions below.  What is the volume of the container?","images":[],"options":{"A":"35 cm3","B":"154 cm3","C":"220 cm3","D":"770 cm3"},"answer":"D","explanation":"Volume of tin = \u03c0r2h = 22/7 x 72 x 5 = 770 cm3","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1995>27","subject":"Mathematics","year":"1995","type":"Objective","topic":"MENSURATION : AREAS","question":"Find the total surface area of a solid circular cone with base radius 3 cm and slant height 4 cm. [Take \u03c0 = 22/7]","images":[],"options":{"A":"375/7 cm2","B":"66 cm2","C":"753/7 cm2","D":"782/7 cm2"},"answer":"B","explanation":"Total surface area of cone = \u03c0rl + \u03c0r2 = \u03c0r(l + r)  r = 3 and l = 4  Area = 22/7 x 3 (4 + 3) = 22/7 x 3 x 7 = 66 cm2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1995>28","subject":"Mathematics","year":"1995","type":"Objective","topic":"MENSURATION : VOLUMES","question":"A hollow sphere has a volume of k cm3 and a surface area of k cm2. Calculate the diameter of the sphere.","images":[],"options":{"A":"3 cm","B":"6 cm","C":"9 cm","D":"More informtion needed."},"answer":"A","explanation":"Volume of sphere = 4/3\u03c0r3  Surface area of sphere = 4\u03c0r2  since the volume and area = k cm3 and k cm2  4/3\u03c0r3 = 4\u03c0r2  4\u03c0r3 = 12\u03c0r2 => r3 = 3r2;  r3 - 3r2 = 0  r2(r - 3) = 0 => r = 3 cm","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1995>29","subject":"Mathematics","year":"1995","type":"Objective","topic":"MENSURATION : VOLUMES","question":"The diagram above shows a cone with the dimensions of its frustrum indicated. Calculate the height of the cone.","images":["data:image/png;base64,"],"options":{"A":"12 cm","B":"15 cm","C":"8 cm","D":"24 cm"},"answer":"D","explanation":"Triangles OAD is similar OBC  \u2234 OAAD = OB But OBBC = OA + OB  Height of cone = OB  Let OA = x;  OB = 12 + x  Hence x6 = 12 + x12 ==> 12x = 6x + 72  6x = 72 => x = 12 cm  Height of cone is DB = 12 + x = (12 + 12) cm = 24 cm","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1995>30","subject":"Mathematics","year":"1995","type":"Objective","topic":"MENSURATION : LONGITUDES AND LATITUDES","question":"The positions of two countries P and Q are (15oN, 12oE) and (65oN, 12oE) respectively. What is the difference in latitude?","images":[],"options":{"A":"104o","B":"100o","C":"80o","D":"50o"},"answer":"D","explanation":"Latitude of P = 15oN; Latitude of Q = 65oN  P and Q both lies in northern hemisphere  Latitudinal difference = 65o - 15o = 50o","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1995>31","subject":"Mathematics","year":"1995","type":"Objective","topic":"MENSURATION : VOLUMES","question":"A 120o sector of a circle of radius 21 cm is bent to form a cone. What is the base radius of the cone?","images":[],"options":{"A":"31/2 cm","B":"7 cm","C":"101/2 cm","D":"14 cm"},"answer":"B","explanation":"PQ = circumference  of the base of cone = 2\u03c0r    PQ = \u03b8/360 x 2\u03c0r = 120/360 x 2 x 22/7 x 21 = 44 cm    \u2234 44 = 2\u03c0r;  44 = 2 x 22/7 x r    44 = 44r/7 ==> r = 7 cm.","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1995>32","subject":"Mathematics","year":"1995","type":"Objective","topic":"MENSURATION : LENGTHS AND PERIMETERS","question":"The angle of a sector of a circle is 108o, if the radius of the circle is 31/2 cm, find the perimeter of the sector.","images":[],"options":{"A":"63/5 cm","B":"64/5 cm","C":"72/10 cm","D":"133/5 cm"},"answer":"D","explanation":"Angle of sector = 108o; Radius of circle = 31/2 cm ==> 7/2 cm    Perimeter of sector = \u03b8/360 x 2\u03c0r + 2r    => 108/360 x 2 x 22/7 x 7/2 + 2(7/2)    => 66 cm/10 + 7 cm = 63/5 + 7 = 133/5","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1995>33","subject":"Mathematics","year":"1995","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram below O is the center of the circle and |BD| = |DC|. If \u2220DCB = 35o, find \u2220BAO.","images":["data:image/png;base64,"],"options":{"A":"20o","B":"25o","C":"30o","D":"35o"},"answer":"A","explanation":"\u2220 DCB =\u2220CBD = 35o (base angles of issoc. triangle are equal)  ADB = 35o + 35o = 70o (ext. angle of a triangle equals two opp. interior angles)  \u2220ABD = 90o (angle in a semi circle is a right angle)  \u2220BAO + \u2220ABD + \u2220ADB = 180o (sum of angles in a triangle)  \u2220BAO + 90o + 70o = 180o  \u2220BAO + 160o = 180o  \u2220BAO = 180o - 160o  \u2220BAO = 20o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1995>34","subject":"Mathematics","year":"1995","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram above, AO is perpendicular to OB. Find x.","images":["data:image/jpeg;base64,"],"options":{"A":"7.5o","B":"15o","C":"22.5o","D":"30o"},"answer":"D","explanation":"Since, OA is \u22a5to OB; \u2234\u2220AOB = 90o.  Hence, 4x + 3x + 2x + 90o = 360o (sum of angles at a point)  9x + 90o = 360o; 9x + 90o = 360o; 9x = 270o ==> x = 30o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1995>35","subject":"Mathematics","year":"1995","type":"Objective","topic":"PLANE GEOMETRY : ANGLES AND INTERCEPTS ON PARALLEL LINES","question":"In the diagram above, PQ is parallel to TU, \u2220PQR = 50o, \u2220QRS = 86o and \u2220STU = 64o. Calculate the value of x.","images":["data:image/png;base64,"],"options":{"A":"136o","B":"120o","C":"108o","D":"100o"},"answer":"D","explanation":"Produce QR and TU to meet at v    \u2234 \u2220VRS = 94o (angle on a straight line)  \u2220VTS = 116o (adjacent angle on a straight line)  \u2234 \u2220RVT = 50o (corresponding angles)  \u2234 94o + 50o + 116o + x = 360o;  x + 260o = 360o; x = 100o","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1995>36","subject":"Mathematics","year":"1995","type":"Objective","topic":"NUMBER AND NUMERATION : LOGARITHMS","question":"If log10x =  2 .3675 and log10y =  2 .9738, what is the value of x + y, correct to three significant figures","images":[],"options":{"A":"0.117","B":"0.118","C":"0.903","D":"0.944"},"answer":"B","explanation":"log10x =  2 .3675 \u2234x = 10 2 .3675 ==> x = 0.02331  log10y =  2 .9738 \u2234y = 10 2 .9738 ==> x = 0.09414.   \u2234x + y = 0.02331 + 0.09414 = 0.11745  = 0.118 (3 s.f)","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1995>37","subject":"Mathematics","year":"1995","type":"Objective","topic":"PLANE GEOMETRY : ANGLES AND INTERCEPTS ON PARALLEL LINES","question":"In the diagram below, AB||CD, the bisector of \u2220BAC and \u2220ACD meet at E. Find the value of \u2220AEC.","images":["data:image/png;base64,"],"options":{"A":"30o","B":"45o","C":"60o","D":"90o"},"answer":"D","explanation":"\u2220BAC = 90o; \u2220ACD = 90o if   AE  and  CE  are the bisectors of \u2220BAC and \u2220ACD respectively  \u2220BAE = 45o; \u2220DCE = 45o \u2234\u2220EAC = \u2220ECA = 45o  But \u2220EAC + \u2220ACE + \u2220AEC = 180 (angle in a \u2206)  \u223445o + 45o + \u2220AEC = 180o  \u2220AEC = 180o - 90o; \u2220AEC = 90o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1995>38","subject":"Mathematics","year":"1995","type":"Objective","topic":"PLANE GEOMETRY : ANGLES AND INTERCEPTS ON PARALLEL LINES","question":"In the diagram above, AB||CD. What is the size of the angle marked x?","images":["data:image/png;base64,"],"options":{"A":"103o","B":"93o","C":"77o","D":"62o"},"answer":"B","explanation":"Since AB is parallel to CD    If P and E are points on CD and AB respectively  \u2234\u2220CPE = 52o (corresponding angles are equal)  \u2234\u2220TPD = 52o (vertically opposite angles are equal)  \u223452o + xo + 35o = 180o (sum of angles in a triangle)  \u2234xo + 87o = 180o; x = 93o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1995>39","subject":"Mathematics","year":"1995","type":"Objective","topic":"PLANE GEOMETRY : LOCI","question":"The locus of a point which is equidistant from two given fixed points is the","images":[],"options":{"A":"Perpendicular bisector of the straight line joining them.","B":"Angle bisector of the straight lines joining them.","C":"Perpendicular to the straight line joining them.","D":"Parallel line to the straight line joining them."},"answer":"A","explanation":"Locus theorem states that: The locus of a point which moves so that it is equidistant from two given fixed points is perpendicular bisector of the straight line joining them.","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1995>40","subject":"Mathematics","year":"1995","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram below, the value of angles b + c is?","images":["data:image/png;base64,"],"options":{"A":"180o","B":"90o","C":"ao","D":"do"},"answer":"A","explanation":"From the figure, \u2220BFD = ao (vertically opposite angles)     \u2220BFC = 180o - ao (adjacent angles on a straight line)  \u2234ao + bo + co + \u2220BFC = 360o (quadrilateral)  ao + bo + co + (180 - a)o = 360o  bo + co = 360o - (180 - a)o - ao  360o - 180o + a - a; b + c = 180o","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1995>41","subject":"Mathematics","year":"1995","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"Which of the following angles is an exterior angle of a regular polygon?","images":[],"options":{"A":"95o","B":"85o","C":"78o","D":"72o"},"answer":"D","explanation":"360nmustbeapositiveinteger  36072=5  \u2234 answer is 72o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1995>42","subject":"Mathematics","year":"1995","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In \u2206 ABC above, BC is produced to D, |AB| = |AC| and \u2220BAC = 50o. Find \u2220ACD.","images":["data:image/png;base64,"],"options":{"A":"50o","B":"60o","C":"65o","D":"115o"},"answer":"D","explanation":"Triangle ABC is issoceles \u2234ACB =  \u2220ABC  \u2220ACD = 180o - \u2220ACB (angle on straight line)  Let \u2220ACB = \u2220ABC = x  \u22342x + 50 = 180o (sum of angles in a triangle)  2x = 130o; x = 65o  \u2234\u2220ACB = 65o ==> \u2220ACD = 180o - 65o = 115o","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1995>43","subject":"Mathematics","year":"1995","type":"Objective","topic":"TRIGONOMETRY : SINE, COSINE AND TANGENT OF AN ANGLE","question":"Withoutusingtables,findthevalueof:sin 20ocos 70o+cos 25osin 65o","images":[],"options":{"A":"2","B":"1","C":"0","D":"-1"},"answer":"A","explanation":"Since sin x = cos (90 - x) (complementary angles)  \u2234sin 20 = cos 70; cos 25 = sin 65  \u2234sin 20cos 70 + cos 25sin 65 = sin 20sin 20 + cos 25cos 25 = 1 + 1 = 2","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1995>44","subject":"Mathematics","year":"1995","type":"Objective","topic":"TRIGONOMETRY : ANGLES OF ELEVATION AND DEPRESSION","question":"In the diagram below, \u2220PRQ = 90o, \u2220QPR = 30o and |PQ| = 10 cm. Find y.","images":["data:image/png;base64,"],"options":{"A":"6 cm","B":"5 cm","C":"4 cm","D":"3 cm"},"answer":"B","explanation":"From the figure, sin 30o = y/10    \u223410 x sin 30o = y ==> y = (10 x 1/2) = 5 cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1995>45","subject":"Mathematics","year":"1995","type":"Objective","topic":"TRIGONOMETRY : BEARINGS","question":"The bearing of two points Q and R from a point P are 030o and 120o respectively. If |PQ| = 12 m and |PR| = 5 m, find the distance QR.","images":[],"options":{"A":"13 m","B":"11 m","C":"9 m","D":"7 m"},"answer":"A","explanation":"From the sketch, \u2220QPR = 90o     \u2234Triangle PQR is right angled P  \u2234Using pythagoras theorem  => QR2 = PQ2 + PR2; \u2234QR2 = 144 + 25 = 169  \u2234QR = \u221a169 = 13 m","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1995>46","subject":"Mathematics","year":"1995","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"What is the mode of the numbers 8, 10, 9, 9, 10, 8, 11, 8, 10, 9, 8, and 14?","images":[],"options":{"A":"8","B":"9","C":"10","D":"11"},"answer":"A","explanation":"8, 8, 8, 8, 8, 9, 9, 9, 10, 10, 10, 11, 14.  Mode is the number with highest frequency  8 occurs four times; 9 occurs three times  10 occurs three times; 11 occurs one time  14 occurs one time; Mode = 8","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1995>47","subject":"Mathematics","year":"1995","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The mean of 20 observations in an experiment is 4. If the observed largest value is 23, find the mean of the remaining observations.","images":[],"options":{"A":"4","B":"3","C":"2.85","D":"2.60"},"answer":"B","explanation":"Total number of observation = 20.  Mean of these observation = 4; Total value = 20 x 4 = 80  One of the values = 23 \u2234 Remaining values = 80 - 23 = 57  No of remaining observation = (20 - 1) = 19    \u2234 mean of remaining observation = 57/19 = 3","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1995>48","subject":"Mathematics","year":"1995","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"Find the median of the following numbers: 2.64, 2.50, 2.72, 2.91, and 2.35","images":[],"options":{"A":"2.91","B":"2.72","C":"2.64","D":"2.50"},"answer":"C","explanation":"2.35, 2.50, 2.64, 2.72, 2.91  ==> numbers in order of magnitude.  Median = middle value; Median = 2.64","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1995>49","subject":"Mathematics","year":"1995","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"Two fair dice are tossed together once. Find the probability that the sum of the outcome is at least 10.","images":[],"options":{"A":"1/12","B":"5/36","C":"1/6","D":"1/4"},"answer":"C","explanation":"Sum of outcome at least 10, means either 10 and higher values.    Probability outcome (sum) atleast 10 ==> 6/36 = 1/6","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1995>50","subject":"Mathematics","year":"1995","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"From a box containing 2 red, 6 white and 5 black balls, a ball is randomly selected. What is the probability that the selected ball is black?","images":[],"options":{"A":"2/13","B":"5/13","C":"5/11","D":"5/6"},"answer":"B","explanation":"2 red, 6 white, 5 black balls  Total number of balls  = 2 + 6 + 5 = 13  Pr(black) = no of black ballstotal no of balls = 513","marks":"1","difficulty":"1"}];